D, M j, Y\" },\r\n  { label: \"YYYY年M月D日 (曜日)\", value: \"Y年n月j日 (l)\" },\r\n];\r\n//プレーンのフォーマット\r\nconst plaineFormats = [\r\n  {\r\n    key: \"str_free\",\r\n    label: __(\"Free String\", \"block-collections\"),\r\n    value: \"%s\",\r\n  },\r\n  {\r\n    key: \"num_comma\",\r\n    label: __(\"Numbers (comma separated)\", \"block-collections\"),\r\n    value: {\r\n      style: \"decimal\",\r\n      useGrouping: true, // カンマ区切り\r\n    },\r\n  },\r\n  {\r\n    key: \"num_no_comma\",\r\n    label: __(\"Numbers (no commas)\", \"block-collections\"),\r\n    value: {\r\n      style: \"decimal\",\r\n      useGrouping: false,\r\n    },\r\n  },\r\n  {\r\n    key: \"num_amount\",\r\n    label: __(\"Amount\", \"block-collections\"),\r\n    value: {\r\n      style: \"currency\",\r\n      currency: \"JPY\",\r\n    },\r\n  },\r\n];\r\n\r\n// 1. フォーマット変更時のオブジェクト型\r\ninterface FormatSettings {\r\n  userFormat: string;\r\n  freeStrFormat: string;\r\n  decimal: number;\r\n}\r\n\r\n// 2. Props の型定義\r\ninterface FormatSelectControlProps {\r\n  titleType: \"plaine\" | \"date\" | \"user\" | string;\r\n  userFormat: string;\r\n  freeStrFormat: string;\r\n  decimal: number;\r\n  onFormatChange: (settings: FormatSettings) => void;\r\n}\r\n\r\nexport const FormatSelectControl = ({\r\n  titleType,\r\n  userFormat,\r\n  freeStrFormat,\r\n  decimal,\r\n  onFormatChange,\r\n}: FormatSelectControlProps) => {\r\n  const isPlaine = titleType === \"plaine\";\r\n  const isDate = titleType === \"date\";\r\n  const isUser = titleType === \"user\";\r\n\r\n  //SelectControlのオプションを生成\r\n  const options = isDate\r\n    ? dateFormats\r\n    : plaineFormats.map((f) => ({ label: f.label, value: f.key }));\r\n\r\n  return (\r\n    <PanelBody title={__(\"Display Format Setting\", \"block-collections\")}>\r\n      {(isPlaine || isDate) && (\r\n        <>\r\n          <SelectControl\r\n            label={__(\"Select Format\", \"block-collections\")}\r\n            value={userFormat}\r\n            options={opt